// src/components/Navbars/EmployeeNavbar.js (ملف جديد)
import React, { useState } from "react";

// ==================== مكون عروض العمل ====================
const JobOffersModal = ({ offers, onAccept, onReject, onClose }) => {
  return (
    <div className="job-offers-overlay" onClick={onClose}>
      <div className="job-offers-container" onClick={(e) => e.stopPropagation()}>
        <button onClick={onClose} className="close-offers-btn">✕</button>
        <h3 className="offers-title">📢 عروض العمل المتاحة</h3>
        <div className="offers-list">
          {offers.map((offer) => (
            <div key={offer.id} className="offer-card">
              <div className="offer-icon">{offer.icon}</div>
              <div className="offer-info">
                <h4 className="offer-restaurant">{offer.restaurantName}</h4>
                <p className="offer-location">📍 {offer.location}</p>
                <p className="offer-position">💼 {offer.position}</p>
                <p className="offer-salary">💰 {offer.salary} DA</p>
                <p className="offer-description">{offer.description}</p>
              </div>
              <div className="offer-actions">
                <button 
                  className="offer-accept-btn"
                  onClick={() => onAccept(offer.id)}
                >
                  ✅ قبول
                </button>
                <button 
                  className="offer-reject-btn"
                  onClick={() => onReject(offer.id)}
                >
                  ❌ رفض
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// ==================== مكون النافبار المعدل للموظف ====================
const EmployeeNavbar = ({ 
  employeeInfo, 
  onUpdateProfile, 
  onLogout,
  jobOffers = [],
  onAcceptOffer,
  onRejectOffer
}) => {
  const [showJobOffers, setShowJobOffers] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [showNotification, setShowNotification] = useState(false);
  const [notificationMessage, setNotificationMessage] = useState("");

  const showNotificationMessage = (message, isSuccess = true) => {
    setNotificationMessage(message);
    setShowNotification(true);
    setTimeout(() => setShowNotification(false), 3000);
  };

  const handleAcceptOffer = (offerId) => {
    if (onAcceptOffer) {
      onAcceptOffer(offerId);
      showNotificationMessage("✅ تم قبول العرض بنجاح! سيتم التواصل معك قريباً", true);
    }
    setShowJobOffers(false);
  };

  const handleRejectOffer = (offerId) => {
    if (onRejectOffer) {
      onRejectOffer(offerId);
      showNotificationMessage("❌ تم رفض العرض", false);
    }
    setShowJobOffers(false);
  };

  const pendingOffersCount = jobOffers.filter(offer => offer.status === "pending").length;

  return (
    <>
      <nav className="employee-navbar">
        <div className="navbar-container">
          {/* Logo */}
          <div className="navbar-logo">
            <a href="/employe/dashboard" className="logo-link">
              <span className="logo-icon">👨‍🍳</span>
              <span className="logo-text">Espace Employé</span>
            </a>
          </div>

          {/* Navigation Links */}
          <div className="navbar-links">
            <a href="/employe/dashboard" className="nav-link">
              <span>📊</span> Tableau de bord
            </a>
            <a href="/employe/missions" className="nav-link">
              <span>📋</span> Mes missions
            </a>
            <a href="/employe/schedule" className="nav-link">
              <span>📅</span> Planning
            </a>
          </div>

          {/* Right Section */}
          <div className="navbar-right">
            {/* Job Offers Button */}
            <button 
              className="job-offers-btn"
              onClick={() => setShowJobOffers(true)}
            >
              <span>🎯</span> عروض العمل
              {pendingOffersCount > 0 && (
                <span className="offers-badge">{pendingOffersCount}</span>
              )}
            </button>

            {/* Profile Menu */}
            <div className="profile-menu-container">
              <button 
                className="profile-btn"
                onClick={() => setShowProfileMenu(!showProfileMenu)}
              >
                <img 
                  src={employeeInfo?.profileImage || "https://randomuser.me/api/portraits/women/68.jpg"} 
                  alt="Profile"
                  className="profile-avatar"
                />
                <span className="profile-name">{employeeInfo?.name?.split(' ')[0] || "Employé"}</span>
                <span className="dropdown-arrow">▼</span>
              </button>

              {showProfileMenu && (
                <div className="profile-dropdown">
                  <div className="dropdown-header">
                    <strong>{employeeInfo?.name}</strong>
                    <span>{employeeInfo?.role}</span>
                  </div>
                  <div className="dropdown-divider"></div>
                  <a href="/employe/profile" className="dropdown-item">
                    <span>👤</span> Mon profil
                  </a>
                  <a href="/employe/settings" className="dropdown-item">
                    <span>⚙️</span> Paramètres
                  </a>
                  <div className="dropdown-divider"></div>
                  <button onClick={onLogout} className="dropdown-item logout">
                    <span>🚪</span> Déconnexion
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* Job Offers Modal */}
      {showJobOffers && (
        <JobOffersModal 
          offers={jobOffers}
          onAccept={handleAcceptOffer}
          onReject={handleRejectOffer}
          onClose={() => setShowJobOffers(false)}
        />
      )}

      {/* Notification */}
      {showNotification && (
        <div className="employee-notification">
          {notificationMessage}
        </div>
      )}

      {/* Styles */}
      <style>{`
        .employee-navbar {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
          backdrop-filter: blur(10px);
          box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
          z-index: 1000;
          padding: 0.75rem 1rem;
          border-bottom: 1px solid rgba(74, 222, 128, 0.3);
        }

        .navbar-container {
          max-width: 1400px;
          margin: 0 auto;
          display: flex;
          justify-content: space-between;
          align-items: center;
          flex-wrap: wrap;
        }

        .logo-link {
          display: flex;
          align-items: center;
          gap: 8px;
          text-decoration: none;
          transition: transform 0.2s;
        }

        .logo-link:hover {
          transform: scale(1.02);
        }

        .logo-icon {
          font-size: 1.8rem;
        }

        .logo-text {
          font-size: 1.2rem;
          font-weight: bold;
          background: linear-gradient(135deg, #4ade80, #22c55e);
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
        }

        .navbar-links {
          display: flex;
          gap: 1.5rem;
          align-items: center;
        }

        .nav-link {
          display: flex;
          align-items: center;
          gap: 8px;
          color: #e2e8f0;
          text-decoration: none;
          padding: 8px 12px;
          border-radius: 12px;
          transition: all 0.2s;
          font-size: 0.9rem;
        }

        .nav-link:hover {
          background: rgba(74, 222, 128, 0.15);
          color: #4ade80;
          transform: translateY(-2px);
        }

        .navbar-right {
          display: flex;
          align-items: center;
          gap: 1rem;
        }

        .job-offers-btn {
          position: relative;
          display: flex;
          align-items: center;
          gap: 8px;
          background: linear-gradient(135deg, #f59e0b, #d97706);
          border: none;
          padding: 8px 16px;
          border-radius: 25px;
          color: white;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.2s;
          font-size: 0.9rem;
        }

        .job-offers-btn:hover {
          transform: scale(1.02);
          filter: brightness(1.05);
          box-shadow: 0 4px 15px rgba(245, 158, 11, 0.4);
        }

        .offers-badge {
          position: absolute;
          top: -6px;
          right: -6px;
          background: #ef4444;
          color: white;
          border-radius: 50%;
          width: 18px;
          height: 18px;
          font-size: 10px;
          display: flex;
          align-items: center;
          justify-content: center;
          font-weight: bold;
        }

        .profile-menu-container {
          position: relative;
        }

        .profile-btn {
          display: flex;
          align-items: center;
          gap: 8px;
          background: rgba(255, 255, 255, 0.1);
          border: 1px solid rgba(74, 222, 128, 0.3);
          padding: 4px 12px 4px 6px;
          border-radius: 40px;
          cursor: pointer;
          transition: all 0.2s;
        }

        .profile-btn:hover {
          background: rgba(74, 222, 128, 0.15);
          border-color: #4ade80;
        }

        .profile-avatar {
          width: 32px;
          height: 32px;
          border-radius: 50%;
          object-fit: cover;
        }

        .profile-name {
          color: white;
          font-size: 0.85rem;
          font-weight: 500;
        }

        .dropdown-arrow {
          color: #4ade80;
          font-size: 0.7rem;
        }

        .profile-dropdown {
          position: absolute;
          top: 50px;
          right: 0;
          background: #1e293b;
          border-radius: 16px;
          min-width: 220px;
          box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
          border: 1px solid rgba(74, 222, 128, 0.2);
          overflow: hidden;
          z-index: 1001;
          animation: dropdownFade 0.2s ease;
        }

        @keyframes dropdownFade {
          from {
            opacity: 0;
            transform: translateY(-10px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .dropdown-header {
          padding: 12px 16px;
          background: rgba(74, 222, 128, 0.1);
        }

        .dropdown-header strong {
          display: block;
          color: white;
          font-size: 0.9rem;
        }

        .dropdown-header span {
          display: block;
          color: #4ade80;
          font-size: 0.75rem;
          margin-top: 4px;
        }

        .dropdown-divider {
          height: 1px;
          background: rgba(255, 255, 255, 0.1);
          margin: 6px 0;
        }

        .dropdown-item {
          display: flex;
          align-items: center;
          gap: 10px;
          padding: 10px 16px;
          color: #e2e8f0;
          text-decoration: none;
          font-size: 0.85rem;
          transition: all 0.2s;
          cursor: pointer;
          width: 100%;
          background: none;
          border: none;
          text-align: left;
        }

        .dropdown-item:hover {
          background: rgba(74, 222, 128, 0.1);
          color: #4ade80;
        }

        .dropdown-item.logout {
          color: #ef4444;
        }

        .dropdown-item.logout:hover {
          background: rgba(239, 68, 68, 0.1);
          color: #ef4444;
        }

        /* Job Offers Modal Styles */
        .job-offers-overlay {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          bottom: 0;
          background: rgba(0, 0, 0, 0.9);
          backdrop-filter: blur(12px);
          z-index: 10000;
          display: flex;
          align-items: center;
          justify-content: center;
          animation: fadeIn 0.3s ease;
        }

        .job-offers-container {
          background: linear-gradient(135deg, #1a1a3a, #0d0d2b);
          border-radius: 30px;
          width: 90%;
          max-width: 800px;
          max-height: 85vh;
          overflow-y: auto;
          padding: 25px;
          border: 2px solid #f59e0b;
          box-shadow: 0 0 40px rgba(245, 158, 11, 0.3);
          animation: slideUp 0.4s ease;
        }

        .close-offers-btn {
          float: right;
          background: none;
          border: none;
          color: white;
          font-size: 24px;
          cursor: pointer;
          transition: all 0.2s;
        }

        .close-offers-btn:hover {
          transform: scale(1.1);
          color: #ef4444;
        }

        .offers-title {
          color: white;
          font-size: 1.5rem;
          text-align: center;
          margin-bottom: 20px;
        }

        .offers-list {
          display: flex;
          flex-direction: column;
          gap: 20px;
        }

        .offer-card {
          background: rgba(255, 255, 255, 0.08);
          border-radius: 20px;
          padding: 20px;
          display: flex;
          gap: 20px;
          transition: all 0.2s;
          border-left: 4px solid #f59e0b;
        }

        .offer-card:hover {
          background: rgba(255, 255, 255, 0.12);
          transform: translateX(5px);
        }

        .offer-icon {
          font-size: 3rem;
        }

        .offer-info {
          flex: 1;
        }

        .offer-restaurant {
          color: #fbbf24;
          font-size: 1.2rem;
          font-weight: bold;
          margin-bottom: 8px;
        }

        .offer-location, .offer-position, .offer-salary {
          color: #e2e8f0;
          font-size: 0.85rem;
          margin-bottom: 4px;
        }

        .offer-description {
          color: #94a3b8;
          font-size: 0.8rem;
          margin-top: 8px;
          line-height: 1.4;
        }

        .offer-actions {
          display: flex;
          flex-direction: column;
          gap: 10px;
          justify-content: center;
        }

        .offer-accept-btn {
          background: linear-gradient(135deg, #22c55e, #15803d);
          border: none;
          padding: 8px 20px;
          border-radius: 25px;
          color: white;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.2s;
        }

        .offer-reject-btn {
          background: linear-gradient(135deg, #ef4444, #b91c1c);
          border: none;
          padding: 8px 20px;
          border-radius: 25px;
          color: white;
          font-weight: bold;
          cursor: pointer;
          transition: all 0.2s;
        }

        .offer-accept-btn:hover, .offer-reject-btn:hover {
          transform: scale(1.02);
          filter: brightness(1.05);
        }

        .employee-notification {
          position: fixed;
          bottom: 30px;
          right: 30px;
          background: #22c55e;
          color: white;
          padding: 12px 24px;
          border-radius: 12px;
          z-index: 10001;
          animation: slideInRight 0.3s ease;
          box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
          font-weight: 500;
        }

        @keyframes slideInRight {
          from {
            transform: translateX(100%);
            opacity: 0;
          }
          to {
            transform: translateX(0);
            opacity: 1;
          }
        }

        @media (max-width: 768px) {
          .navbar-links {
            display: none;
          }
          .job-offers-btn span:first-child {
            display: none;
          }
          .profile-name {
            display: none;
          }
          .logo-text {
            display: none;
          }
          .offer-card {
            flex-direction: column;
            text-align: center;
          }
          .offer-actions {
            flex-direction: row;
          }
        }
      `}</style>
    </>
  );
};

export default EmployeeNavbar;
